var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하아앗……!","JPN":"はああっ……！","ENG":"Hraagh...!","TWN":"嚇啊啊……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"으윽! 학부장님! 제가 잔해가 되어서 녀석을 막겠습니다!","JPN":"ぐうっ！　学部長！　私が残骸になりやつを止めます！","ENG":"Ngh! Sir! I'll become a Remains to stop him!","TWN":"呃啊！院長！我來變成殘骸擋住他！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"시간벌이 정도는 할 수 있을 겁니다!","JPN":"時間稼ぎにはなるでしょう！","ENG":"It'll be enough to buy you some time!","TWN":"應該可以爭取點時間！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그러니 어서 자리를 피하십시오!","JPN":"だから、早くお逃げください！","ENG":"So please! Get away from here!","TWN":"所以請快離開吧！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"어딜! 제 앞에서 그게 마음대로 될 것 같습니까!","JPN":"させません！　私の前でそれができるとでもお思いか！","ENG":"Oh, no you don't! Do you really think that plan will work against me?","TWN":"想逃！有我在，你想逃去哪！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"반성하십시오!","JPN":"反省しなさい！","ENG":"You must reflect on your choices!","TWN":"請反省吧！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……크헉!","JPN":"……ぐはっ！","ENG":"...Kuh!","TWN":"……咳！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"다 끝났습니다. 이제 포기하십시오.","JPN":"ここまでです。もう諦めてください。","ENG":"It's over. Give up.","TWN":"都結束了，放棄吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"내가 부탁하지 않았나? 순순히 비켜달라고.","JPN":"私はお願いしたはずだ。大人しく道を譲ってくれと。","ENG":"Do I have to repeat myself? I asked you to move aside.","TWN":"我不是拜託過你了嗎？請你乖乖讓開。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"으음? 뭐라고?","JPN":"む？　なんだと？","ENG":"Mm? What did you say?","TWN":"嗯？你說什麼？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"전원! 제 뒤로 피하십시오! 무언가 숨겨둔 수가 있습니다!","JPN":"全員！　私の後ろに隠れてください！　何か来ます！","ENG":"Everyone! Get behind me! He's hiding something!","TWN":"所有人！躲到我後面去！他可能還藏著什麼手段！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"크으으윽……!!","JPN":"くうううっ……！！","ENG":"Krrgh...!!","TWN":"咳呃呃呃……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"내 공격을 피하지 않고, 정면에서 받아내다니 꽤 튼튼한 육체를 가졌군.","JPN":"私の攻撃を、正面から受け止めるとはなかなか丈夫な肉体だ。","ENG":"What a sturdy body you have. Taking my attack head-on instead of avoiding it.","TWN":"沒有躲避我的攻擊，而是正面迎戰，肉體還挺結實。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"필시 하루도 빠짐없이 꾸준히 단련한 몸이겠지. 좋은 승부가 되겠어.","JPN":"きっと一日も欠かさずに鍛錬したのだろう。良い勝負になりそうだ。","ENG":"You must have trained your body every day. I believe this will be a good fight.","TWN":"是每天都堅持鍛煉肉體嗎？很好，我很期待這一場的勝負。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"그렇지 않나, 기관의 사냥개?","JPN":"そう思わないか？　機関の猟犬。","ENG":"Don't you also think so, hound of the Institution?","TWN":"你覺得呢，機關的獵犬？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"철학부, 고고학부, 예술학부, 건축학부…….","JPN":"哲学部、考古学部、芸術学部、建築学部……","ENG":"The Department of Philosophy, Archeology, Arts, and Architecture...","TWN":"哲學院，考古學院，藝術學院，建築學院……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이상하군요. 숙청당한 학부 중에 아직도 당신 같은 학부장급 실력자가 남아 있었습니까?","JPN":"変ですね。粛清された学部の中に、まだあなたのような学部長級の実力者が残っていたとは。","ENG":"That's odd. Among the departments that were purged, was there still a dean-level person like you left?","TWN":"奇怪，被肅清的學院中，還存在像你這樣的院長級目標嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"지금이다!","JPN":"今だ！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님이 시간을 벌어주는 동안 고고학부장을 쏴 버려!","JPN":"エージェントが時間を稼いでくれている間に、考古学部長を撃て！","ENG":"Shoot the Dean of Archeology while Agent Ferrier buys us time!","TWN":"趁著特工在爭取時間，趕緊將考古學教授射殺！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"성찬의 때가 왔다!","JPN":"聖餐の時が来た！","ENG":"It is time for the feast!","TWN":"盛宴的時刻到了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"모두 죽음을 두려워하지 말지어다! 어머니께서 우리를 하나로 인도하신다!","JPN":"皆、死を恐れるな！　母が我々を一つに導く！","ENG":"Fear not death, everyone! Mother will guide us to one!","TWN":"大家不要懼怕死亡！母親正引導我們走向合一！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"우리는 어머니 안에서 새롭게 잉태되리니!","JPN":"我々は母の中で生まれ変わるのだ！","ENG":"We will be born from Mother's womb anew!","TWN":"我們要在母親地懷抱裡重生！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"이 자식들! 카운터도 아닌데 총알을 피하지 않는다고?","JPN":"こいつら！　カウンターでもないのに、銃弾を避けないぞ！","ENG":"What the hell?! Those bastards aren't Counters, but they don't avoid our bullets!","TWN":"你們這些傢伙！連制裁者都不是，不怕子彈的嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"제임스. 우리 측 신자들을 붙여주겠다.","JPN":"ジェームス。我が信者をつけてやろう。","ENG":"James. I will send some of our followers to you.","TWN":"詹姆斯，我派幾個我們的信徒給你。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"네 놈은 먼저 가서 <color=#ffd34c>성배</color>를 확보하도록.","JPN":"貴様は先に向かい、<color=#ffd34c>聖杯</color>を確保しろ。","ENG":"Go ahead and secure the <color=#ffd34c>Holy Grail</color>.","TWN":"你先去取<color=#ffd34c>聖杯</color>。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"나는 어머니가 눈을 뜨기 위해 필요한 밑준비를 마치지.","JPN":"俺はお母さんが目覚めるのに必要な下準備を済ませておく。","ENG":"I will finalise the preparations for Mother's awakening.","TWN":"由我來做喚醒母親所需的準備吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"알겠네. 그럼 우리가 다시 보는 건 의식이 시작하는 순간이 되겠군.","JPN":"わかった。では、私たちが再び会うのは儀式が始まるときだな。","ENG":"All right. Then we will meet again when the ritual starts.","TWN":"好吧，那我們重遇的時候，就是儀式開始的那一刻了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"먼저 실례하겠네.","JPN":"先に失礼する。","ENG":"Excuse me.","TWN":"那我失陪了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"어딜 도망칩니까, 제임스!","JPN":"逃がしません、ジェームス！","ENG":"You can't run away from me, James!","TWN":"往哪裡，詹姆斯！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"이 앞은 못 지나간다. 사냥개.","JPN":"ここから先は通さんぞ。猟犬。","ENG":"You will not take another step forward, hound.","TWN":"你是過不去的，獵犬。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"마치, 큰 벽을 앞에 두고 있는 것 같은…… 이 막막한 느낌.","JPN":"まるで、大きな壁を目の前にしているような……この無力感。","ENG":"This feeling of hopelessness... as if I'm faced against a large wall...","TWN":"這種面對著一堵大牆一樣的……茫然的感覺。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L28_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이상하군. 분명 처음일 텐데 왜 익숙한 기분이지.","JPN":"変だ。初めてのはずなのに、どうしてこんなにも懐かしいのだろう。","ENG":"Strange. I feel like I know him even though I've never met him before.","TWN":"奇怪，明明是第一次見，但為什麼感覺這麼熟悉。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"당장 기관에게 연락하십시오. 증원을 요청해서 제임스를 뒤쫓아야 합니다!","JPN":"今すぐ機関に連絡してください。増援を要請して、ジェームスを追いかけなければ！","ENG":"Contact the Institution right now. Request for reinforcements to chase after James!","TWN":"請立即聯繫機關，我們需要增援追捕詹姆斯！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L32_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 페리어 요원님!","JPN":"わかりました。フェリエー様！","ENG":"Yes, sir!","TWN":"明白了，佩里特工！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"지금부터 싸움이 길어질 것 같은데, 서로 통성명이라도 어떻습니까?","JPN":"この戦いは長くなりそうですね。まずはお互い、初対面の挨拶をするのはどうでしょう。","ENG":"I believe our fight will take a while. So how about we introduce ourselves?","TWN":"從現在開始，沒打個一時半刻應該不會結束，要不先互相報上姓名怎麼樣？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"저는 라이언 페리어. 이 자리에서 당신을 쓰러트리겠습니다.","JPN":"私はライアン・フェリエー。この場であなたを倒します。","ENG":"I am Ryan Ferrier. The man who will defeat you here.","TWN":"我是瑞安·佩里，我會在這裡打倒你。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"재밌군. 사냥개 주제에 기사도 흉내를 내려는 건가?","JPN":"面白い。猟犬が騎士の真似ごととは。","ENG":"Funny. A hound pretending to be a knight.","TWN":"有意思。區區一條獵犬，也想模仿騎士信條嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"원래 이름은 버렸다.","JPN":"元の名は捨てた。","ENG":"I've thrown away my name.","TWN":"我已經拋棄了原來的名字。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"지금의 나는 지식의 호수를 지키는 기사…….","JPN":"今の俺は知識の湖を守る騎士……","ENG":"I am now... the knight that guards the Lake of Knowledge...","TWN":"現在的我，只是守護知識湖水的騎士……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"호수의 기사일 뿐이다.","JPN":"湖の騎士だ。","ENG":"I am the Knight of the Lake.","TWN":"我是湖水騎士。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};